const Register = () => {
  return (
    <div className="container">
      <h2>Register Page</h2>
      <input placeholder="Name" />
      <input placeholder="Email" />
      <input placeholder="Password" type="password" />
      <button>Register</button>
    </div>
  );
};

export default Register;
